# weather_mcp.py
import asyncio
from mcp.server import Server
from mcp.server.stdio import stdio_server
from mcp import types
import httpx

# 建立 MCP server
server = Server('weather-server')

@server.list_tools()
async def list_tools() -> list[types.Tool]:
    """列出可用工具"""
    return [
        types.Tool(
            name='get_weather',
            description='獲取指定城市嘅天氣',
            inputSchema={
                'type': 'object',
                'properties': {
                    'city': {
                        'type': 'string',
                        'description': '城市名稱，例如 Hong Kong'
                    }
                },
                'required': ['city']
            }
        )
    ]

@server.call_tool()
async def call_tool(name: str, arguments: dict) -> list[types.TextContent]:
    """執行工具"""
    if name == 'get_weather':
        city = arguments['city']

        # 調用天氣 API
        async with httpx.AsyncClient() as client:
            response = await client.get(
                f'https://wttr.in/{city}?format=3'
            )

        return [
            types.TextContent(
                type='text',
                text=f'{city} 天氣：{response.text}'
            )
        ]

    raise ValueError(f'Unknown tool: {name}')

async def main():
    async with stdio_server() as (read_stream, write_stream):
        await server.run(
            read_stream,
            write_stream,
            server.create_initialization_options()
        )

if __name__ == '__main__':
    asyncio.run(main())

from mcp.server import Server
from mcp import types
import json

server = Server('company-knowledge')

@server.list_resources()
async def list_resources() -> list[types.Resource]:
    return [
        types.Resource(
            uri='company://handbook',
            name='公司員工手冊',
            description='包括假期、福利、行為準則',
            mimeType='text/plain'
        ),
        types.Resource(
            uri='company://products',
            name='產品目錄',
            description='所有產品嘅詳細資訊',
            mimeType='application/json'
        )
    ]

@server.read_resource()
async def read_resource(uri: str) -> str:
    if uri == 'company://handbook':
        with open('handbook.txt', 'r') as f:
            return f.read()
    elif uri == 'company://products':
        with open('products.json', 'r') as f:
            return f.read()
    raise ValueError(f'Unknown resource: {uri}')

// calculator_server.ts
import { Server } from '@modelcontextprotocol/sdk/server/index.js';
import { StdioServerTransport } from '@modelcontextprotocol/sdk/server/stdio.js';
import { CallToolRequestSchema, ListToolsRequestSchema } from '@modelcontextprotocol/sdk/types.js';

const server = new Server(
  { name: 'calculator', version: '1.0.0' },
  { capabilities: { tools: {} } }
);

server.setRequestHandler(ListToolsRequestSchema, async () => ({
  tools: [{
    name: 'calculate',
    description: '計算數學表達式',
    inputSchema: {
      type: 'object',
      properties: {
        expression: { type: 'string', description: '數學表達式，例如 2+2*3' }
      },
      required: ['expression']
    }
  }]
}));

server.setRequestHandler(CallToolRequestSchema, async (request) => {
  if (request.params.name === 'calculate') {
    const expr = request.params.arguments?.expression as string;
    const result = eval(expr);  // 實際生產唔建議用 eval
    return { content: [{ type: 'text', text: `${expr} = ${result}` }] };
  }
  throw new Error(`Unknown tool: ${request.params.name}`);
});

const transport = new StdioServerTransport();
await server.connect(transport);
